app.post("/admin/login", async (req, res) => {
  const auth = await emailAuth("login", req.body);
  if (!auth.ok) return authFail(req, res, auth);
  const access = await accessFromToken(auth.accessToken);
  if (!isAdmin(access)) return res.status(403).type("html").send(responsePage("Admin access denied", "This account is not an owner, admin, or founder.", [link("/admin/login", "Back")]));
  setCookie(res, ADMIN_COOKIE, auth.accessToken, auth.expiresIn);
  await insert("admin_audit_logs", { actor_id: access.user.id, action: "admin.login.succeeded", target_type: "admin_session", metadata: { method: "email" } });
  return res.redirect(303, "/admin");
});
