app.post("/support", requireCustomer, async (req, res) => {
  if (!clean(req.body.subject) || !clean(req.body.message)) return jsonOrHtml(req, res, 400, { ok: false, code: "validation_failed", message: "Subject and message are required." });
  const saved = await insert("support_requests", { organization_id: req.access.organizationId, user_id: req.access.user.id, subject: clean(req.body.subject), message: clean(req.body.message), status: "open" });
  if (!saved.ok) return jsonOrHtml(req, res, 503, setup("account_database"));
  await addActivity(req.access, "support.created", { subject: clean(req.body.subject).slice(0, 120) });
  return jsonOrHtml(req, res, 200, { ok: true, message: "Support request saved." }, "/dashboard");
});

