app.post("/api/billing/create-checkout-session", requireCustomer, async (req, res) => {
  const key = clean(req.body.product || req.body.product_key || req.body.priceKey || req.body.plan);
  const product = PRODUCTS[key];
  if (!product) return res.status(400).json({ ok: false, code: "invalid_product" });
  const price = priceId(key);
  if (!stripeOk()) return res.status(503).json(setup("payment_connection"));
  if (!price) return res.status(503).json({ ok: false, code: "setup_required", service: "stripe_price", env: product[3] });
  const customer = await stripeCustomer(req.access, true);
  if (!customer.ok) return res.status(503).json(setup("stripe_customer"));
  const session = await checkoutSession(req, key, customer.stripeCustomerId, price);
  if (!session.ok) return res.status(502).json({ ok: false, code: "checkout_unavailable" });
  return res.json({ ok: true, checkoutUrl: session.url, checkout_url: session.url });
});
app.post("/api/billing/create-portal-session", requireCustomer, async (req, res) => {
  if (!stripeOk()) return res.status(503).json(setup("payment_connection"));
  const customer = await stripeCustomer(req.access, false);
  if (!customer.ok) return res.status(404).json({ ok: false, code: "stripe_customer_missing" });
  const response = await stripe("/v1/billing_portal/sessions", new URLSearchParams({ customer: customer.stripeCustomerId, return_url: `${publicUrl(req)}/business-builder/billing` }));
  if (!response.ok) return res.status(502).json({ ok: false, code: "portal_unavailable" });
  return res.json({ ok: true, portalUrl: response.body.url, portal_url: response.body.url });
});
