async function requireCustomer(req, res, next) { const a = await resolveAccess(req, CUSTOMER_COOKIE); if (a.ok) { req.access = a; return next(); } if (ready().accountDatabase === "missing") return setupPage(req, res); return wantsJson(req) ? res.status(401).json({ ok: false, code: "auth_required" }) : res.redirect(303, "/login"); }
async function requireAdmin(req, res, next) { const a = await resolveAccess(req, ADMIN_COOKIE); if (isAdmin(a)) { req.access = a; return next(); } return wantsJson(req) ? res.status(a.setupRequired ? 503 : 401).json({ ok: false, code: a.setupRequired ? "setup_required" : "admin_auth_required" }) : res.redirect(303, "/admin/login"); }
async function resolveAccess(req, cookieName) { if (!supabaseAuth().ok) return { ok: false, setupRequired: true }; const token = bearer(req) || cookie(req, cookieName); return token ? accessFromToken(token) : { ok: false }; }
async function accessFromToken(token) { const u = await supabaseUser(token); if (!u.ok) return { ok: false }; const workspace = await ensureWorkspace(u.user); const roles = await rolesFor(u.user, workspace.organizationId); return { ok: true, user: u.user, organizationId: workspace.organizationId, roles }; }
function isAdmin(a) { return Boolean(a?.ok && a.roles?.some((r) => ["owner", "admin", "founder"].includes(r))); }

async function emailAuth(mode, body) { const email = clean(body.email).toLowerCase(); const password = String(body.password || ""); if (!/^\S+@\S+\.\S+$/.test(email) || password.length < 6) return { ok: false, status: 400, message: "Valid email and password are required." }; const cfg = supabaseAuth(); if (!cfg.ok) return { ok: false, status: 503, message: "Supabase auth setup required." }; const path = mode === "signup" ? "/auth/v1/signup" : "/auth/v1/token?grant_type=password"; const r = await fetch(`${cfg.url}${path}`, { method: "POST", headers: { apikey: cfg.anonKey, Authorization: `Bearer ${cfg.anonKey}`, "Content-Type": "application/json" }, body: JSON.stringify({ email, password }) }).catch(() => null); const p = await r?.json?.().catch(() => ({})); if (!r?.ok) return { ok: false, status: r?.status || 502, message: p.error_description || p.msg || "Email authentication failed." }; const token = p.access_token || p.session?.access_token; const user = p.user || p; if (!token || !user?.id) return { ok: false, status: 202, message: "Check your email to confirm the account before logging in." }; await ensureWorkspace(user, body.full_name); return { ok: true, user, accessToken: token, expiresIn: p.expires_in || COOKIE_MAX_AGE }; }
function finishAuth(req, res, auth, dest) { if (!auth.ok) return authFail(req, res, auth); setCookie(res, CUSTOMER_COOKIE, auth.accessToken, auth.expiresIn); return wantsJson(req) ? res.json({ ok: true, redirect: dest }) : res.redirect(303, dest); }
function authFail(req, res, a) { const status = a.status || 401; return wantsJson(req) ? res.status(status).json({ ok: false, code: status === 503 ? "setup_required" : "auth_failed", message: a.message }) : res.status(status).type("html").send(responsePage("Access not ready", a.message || "Authentication failed.", [link("/login", "Login"), link("/signup", "Signup")])); }

async function ensureWorkspace(user, fullName = "") { const cfg = supabaseAdmin(); const userId = clean(user?.id); const email = clean(user?.email).toLowerCase(); if (!cfg.ok || !uuid(userId)) return { organizationId: null }; await upsert("profiles", { id: userId, email, full_name: clean(fullName || user?.user_metadata?.full_name), updated_at: new Date().toISOString() }, "id"); const m = await select("organization_memberships", `select=organization_id,role&user_id=eq.${encodeURIComponent(userId)}&limit=1`); if (m.rows?.[0]?.organization_id) return { organizationId: m.rows[0].organization_id }; const org = await insert("organizations", { name: email ? `${email.split("@")[0]} workspace` : "SONARA workspace", slug: `org-${userId.slice(0, 8)}`, owner_id: userId }); if (org.row?.id) await upsert("organization_memberships", { organization_id: org.row.id, user_id: userId, role: founders().has(email) ? "founder" : "customer" }, "organization_id,user_id"); return { organizationId: org.row?.id || null }; }
async function rolesFor(user, orgId) { const roles = new Set(["customer"]); const email = clean(user.email).toLowerCase(); if (founders().has(email)) ["founder", "admin", "owner"].forEach((r) => roles.add(r)); if (admins().has(email)) roles.add("admin"); if (orgId) { const rows = await select("organization_memberships", `select=role&organization_id=eq.${encodeURIComponent(orgId)}&user_id=eq.${encodeURIComponent(user.id)}`); rows.rows?.forEach((r) => ROLE_SET.has(r.role) && roles.add(r.role)); } return [...roles]; }
async function paid(access, product) { if (access.roles.some((r) => ["paid_customer", "owner", "admin", "founder"].includes(r))) return { ok: true, source: "role" }; const s = await select("subscriptions", `select=status&organization_id=eq.${encodeURIComponent(access.organizationId)}`); if (s.rows?.some((r) => ["active", "trialing"].includes(r.status))) return { ok: true, source: "subscription" }; const p = await select("purchases", `select=status,product_key&organization_id=eq.${encodeURIComponent(access.organizationId)}&product_key=eq.${encodeURIComponent(product)}`); if (p.rows?.some((r) => ["paid", "complete", "completed", "succeeded"].includes(r.status))) return { ok: true, source: "purchase" }; return { ok: false, source: "billing_state_missing" }; }

function ready() { return { ok: true, accountDatabase: supabaseAdmin().ok && supabaseAuth().ok ? "configured" : "missing", paymentConnection: stripeOk() ? "configured" : "missing", paymentUpdates: env("STRIPE_WEBHOOK_SECRET")?.startsWith("whsec_") ? "configured" : "missing", emailDelivery: env("RESEND_API_KEY") && env("RESEND_FROM_EMAIL") ? "configured" : "missing", googleSignIn: env("GOOGLE_CLIENT_ID") && env("GOOGLE_CLIENT_SECRET") ? "configured" : "deferred", founderAccess: founders().size || admins().size ? "configured" : "missing" }; }
function envStatus() { return { NEXT_PUBLIC_SUPABASE_URL: Boolean(env(["NEXT_PUBLIC_SUPABASE_URL", "SUPABASE_URL"])), NEXT_PUBLIC_SUPABASE_ANON_KEY: Boolean(env(["NEXT_PUBLIC_SUPABASE_ANON_KEY", "SUPABASE_ANON_KEY"])), SUPABASE_SERVICE_ROLE_KEY: Boolean(env("SUPABASE_SERVICE_ROLE_KEY")), STRIPE_SECRET_KEY: stripeOk(), STRIPE_WEBHOOK_SECRET: Boolean(env("STRIPE_WEBHOOK_SECRET")), RESEND_API_KEY: Boolean(env("RESEND_API_KEY")), RESEND_FROM_EMAIL: Boolean(env("RESEND_FROM_EMAIL")), NEXT_PUBLIC_SITE_URL: Boolean(env(["NEXT_PUBLIC_SITE_URL", "PUBLIC_SITE_URL", "APP_URL"])), FOUNDER_EMAILS: founders().size > 0 }; }
async function productDashboard(req, res, slug, company) { const c = await counts(req.access.organizationId); const events = await activity(req.access.organizationId); const access = await paid(req.access, company.product); return page(res, `${company.name} Dashboard`, "Auth-aware dashboard", `${company.name} dashboard`, "Real auth, real database records when configured, and honest empty states.", [roleCard(req.access), card("Free customer access", "Free planning and readiness tools are enabled for logged-in users."), card("Free tools", company.free), gate("Paid tools", company.paid, access.ok), card("Records", c.ok ? `Intake: ${c.intake}. Checklist: ${c.checklist}. Support: ${c.support}.` : "Database setup required before records can be counted."), activityCard(events), card("Next actions", next(c, access))], [link("/business-builder/intake", "Intake"), link("/business-builder/launch-readiness", "Launch checklist"), link("/business-builder/billing", "Billing"), link("/support", "Help/support"), logout()]); }
async function counts(org) { if (!org || !supabaseAdmin().ok) return { ok: false }; return { ok: true, intake: await count("intake_requests", `organization_id=eq.${encodeURIComponent(org)}`), checklist: await count("launch_checklist_items", `organization_id=eq.${encodeURIComponent(org)}`), support: await count("support_requests", `organization_id=eq.${encodeURIComponent(org)}`) }; }
function next(c, access) { if (!c.ok) return "Configure Supabase and run migrations."; if (!c.intake) return "Submit your first intake request."; if (!access.ok) return "Use free tools or upgrade when Stripe is configured."; return "Review activity and keep the launch checklist current."; }
async function checklist(org) { if (!org || !supabaseAdmin().ok) return { ok: false, items: [] }; const r = await select("launch_checklist_items", `select=id,category,title,description,status,due_date,created_at,updated_at&organization_id=eq.${encodeURIComponent(org)}&order=created_at.desc`); return { ok: r.ok, items: r.rows || [] }; }
async function activity(org) { if (!org || !supabaseAdmin().ok) return []; const r = await select("activity_events", `select=event_type,event_data,created_at&organization_id=eq.${encodeURIComponent(org)}&order=created_at.desc&limit=10`); return r.rows || []; }
async function addActivity(a, type, data = {}) { return a?.organizationId ? insert("activity_events", { organization_id: a.organizationId, user_id: a.user?.id || null, event_type: type, event_data: data }) : { ok: false }; }
async function billing(a) { if (!a.organizationId || !supabaseAdmin().ok) return { ok: false, message: "Database setup required before billing state can be shown." }; const s = await select("subscriptions", `select=status,price_id,current_period_end&organization_id=eq.${encodeURIComponent(a.organizationId)}&order=created_at.desc&limit=5`); const p = await select("purchases", `select=status,product_key,price_id&organization_id=eq.${encodeURIComponent(a.organizationId)}&order=created_at.desc&limit=5`); return { ok: true, subscriptions: s.rows || [], purchases: p.rows || [] }; }

async function stripeCustomer(a, create) { const existing = await select("stripe_customers", `select=stripe_customer_id&organization_id=eq.${encodeURIComponent(a.organizationId)}&limit=1`); if (existing.rows?.[0]?.stripe_customer_id) return { ok: true, stripeCustomerId: existing.rows[0].stripe_customer_id }; if (!create) return { ok: false }; const r = await stripe("/v1/customers", new URLSearchParams({ email: a.user.email || "", "metadata[user_id]": a.user.id, "metadata[organization_id]": a.organizationId })); if (!r.ok || !r.body.id) return { ok: false }; await insert("stripe_customers", { user_id: a.user.id, organization_id: a.organizationId, stripe_customer_id: r.body.id }); return { ok: true, stripeCustomerId: r.body.id }; }
async function checkoutSession(req, key, customer, price) { const product = PRODUCTS[key]; const params = new URLSearchParams({ mode: product[2], customer, success_url: `${publicUrl(req)}/business-builder/billing?checkout=success`, cancel_url: `${publicUrl(req)}/pricing?checkout=cancelled`, "line_items[0][price]": price, "line_items[0][quantity]": "1", "metadata[product_key]": product[0], "metadata[price_key]": key, "metadata[price_id]": price }); if (product[2] === "subscription") { params.set("subscription_data[metadata][product_key]", product[0]); params.set("subscription_data[metadata][price_key]", key); params.set("subscription_data[metadata][price_id]", price); } const r = await stripe("/v1/checkout/sessions", params); return r.ok ? { ok: true, url: r.body.url } : { ok: false }; }
async function stripeWebhook(req, res) { const secret = env("STRIPE_WEBHOOK_SECRET"); if (!secret?.startsWith("whsec_")) return res.status(503).json(setup("payment_updates")); if (!verifySig(req.body, req.get("stripe-signature"), secret)) return res.status(400).json({ ok: false, code: "invalid_signature" }); let event; try { event = JSON.parse(req.body.toString("utf8")); } catch { return res.status(400).json({ ok: false, code: "invalid_payload" }); } const result = await applyStripe(event); return res.json({ ok: true, received: true, synchronized: result.ok }); }
async function applyStripe(event) { const obj = event.data?.object || {}; const customer = clean(obj.customer); const mapped = customer ? await select("stripe_customers", `select=user_id,organization_id&stripe_customer_id=eq.${encodeURIComponent(customer)}&limit=1`) : { rows: [] }; const row = mapped.rows?.[0] || {}; if (event.type === "checkout.session.completed") { if (obj.mode === "payment") await upsert("purchases", { user_id: row.user_id || null, organization_id: row.organization_id || null, stripe_checkout_session_id: obj.id, stripe_payment_intent_id: obj.payment_intent || null, product_key: obj.metadata?.product_key || "unknown", price_id: obj.metadata?.price_id || null, status: obj.payment_status || "completed" }, "stripe_checkout_session_id"); if (obj.mode === "subscription") await upsert("subscriptions", { user_id: row.user_id || null, organization_id: row.organization_id || null, stripe_subscription_id: obj.subscription, stripe_customer_id: customer, status: obj.status || "active", price_id: obj.metadata?.price_id || null }, "stripe_subscription_id"); }
  if (event.type.startsWith("customer.subscription.")) await upsert("subscriptions", { user_id: row.user_id || null, organization_id: row.organization_id || null, stripe_subscription_id: obj.id, stripe_customer_id: customer, status: obj.status, price_id: obj.items?.data?.[0]?.price?.id || null, current_period_end: obj.current_period_end ? new Date(obj.current_period_end * 1000).toISOString() : null, updated_at: new Date().toISOString() }, "stripe_subscription_id");
  if (["invoice.payment_succeeded", "invoice.payment_failed"].includes(event.type) && row.organization_id) await insert("activity_events", { organization_id: row.organization_id, user_id: row.user_id || null, event_type: `stripe.${event.type}`, event_data: { invoice: obj.id, customer, status: obj.status } });
  if (row.organization_id) await insert("activity_events", { organization_id: row.organization_id, user_id: row.user_id || null, event_type: `stripe.${event.type}`, event_data: { id: event.id, object: obj.object } }); return { ok: true }; }
async function overview() { const [users, orgs, subs, purchases, intake, support, events, audit] = await Promise.all([count("profiles"), count("organizations"), count("subscriptions", "status=in.(active,trialing)"), count("purchases"), count("intake_requests"), count("support_requests"), select("activity_events", "select=event_type,event_data,created_at&order=created_at.desc&limit=10"), select("admin_audit_logs", "select=action,target_type,created_at&order=created_at.desc&limit=10")]); return { counts: { users, organizations: orgs, activeSubscriptions: subs, purchases, intakeRequests: intake, supportRequests: support }, recentActivity: events.rows || [], auditLogs: audit.rows || [] }; }

function supabaseAuth() { const url = env(["SUPABASE_URL", "NEXT_PUBLIC_SUPABASE_URL"]); const anonKey = env(["SUPABASE_ANON_KEY", "NEXT_PUBLIC_SUPABASE_ANON_KEY"]); return url && anonKey ? { ok: true, url: url.replace(/\/$/, ""), anonKey } : { ok: false }; }
function supabaseAdmin() { const a = supabaseAuth(); const key = env("SUPABASE_SERVICE_ROLE_KEY"); return a.ok && key ? { ok: true, url: a.url, key } : { ok: false }; }
function headers(prefer = "") { const c = supabaseAdmin(); const h = { apikey: c.key, Authorization: `Bearer ${c.key}`, "Content-Type": "application/json" }; if (prefer) h.Prefer = prefer; return h; }
async function supabaseUser(token) { const c = supabaseAuth(); if (!c.ok) return { ok: false }; const r = await fetch(`${c.url}/auth/v1/user`, { headers: { apikey: c.anonKey, Authorization: `Bearer ${token}` } }).catch(() => null); return r?.ok ? { ok: true, user: await r.json() } : { ok: false }; }
async function select(table, query) { const c = supabaseAdmin(); if (!c.ok || !safeTable(table)) return { ok: false, rows: [] }; const r = await fetch(`${c.url}/rest/v1/${table}?${query}`, { headers: headers() }).catch(() => null); return r?.ok ? { ok: true, rows: await r.json().catch(() => []) } : { ok: false, rows: [] }; }
async function insert(table, row) { const c = supabaseAdmin(); if (!c.ok || !safeTable(table)) return { ok: false }; const r = await fetch(`${c.url}/rest/v1/${table}`, { method: "POST", headers: headers("return=representation"), body: JSON.stringify(row) }).catch(() => null); const rows = await r?.json?.().catch(() => []); return r?.ok ? { ok: true, row: rows[0] || null } : { ok: false }; }
async function upsert(table, row, conflict) { const c = supabaseAdmin(); if (!c.ok || !safeTable(table)) return { ok: false }; const r = await fetch(`${c.url}/rest/v1/${table}?on_conflict=${encodeURIComponent(conflict)}`, { method: "POST", headers: headers("resolution=merge-duplicates,return=representation"), body: JSON.stringify(row) }).catch(() => null); const rows = await r?.json?.().catch(() => []); return r?.ok ? { ok: true, row: rows[0] || null } : { ok: false }; }
async function patch(table, filter, data) { const c = supabaseAdmin(); if (!c.ok || !safeTable(table)) return { ok: false }; const r = await fetch(`${c.url}/rest/v1/${table}?${filter}`, { method: "PATCH", headers: headers("return=representation"), body: JSON.stringify(data) }).catch(() => null); const rows = await r?.json?.().catch(() => []); return r?.ok ? { ok: true, row: rows[0] || null } : { ok: false }; }
async function del(table, filter) { const c = supabaseAdmin(); if (!c.ok || !safeTable(table)) return { ok: false }; const r = await fetch(`${c.url}/rest/v1/${table}?${filter}`, { method: "DELETE", headers: headers() }).catch(() => null); return { ok: Boolean(r?.ok) }; }
async function count(table, filter = "") { const c = supabaseAdmin(); if (!c.ok || !safeTable(table)) return 0; const q = filter ? `?select=id&${filter}&limit=1` : "?select=id&limit=1"; const r = await fetch(`${c.url}/rest/v1/${table}${q}`, { headers: headers("count=exact") }).catch(() => null); return Number(r?.headers?.get?.("content-range")?.match(/\/(\d+)$/)?.[1] || 0); }
async function stripe(path, params) { const r = await fetch(`https://api.stripe.com${path}`, { method: "POST", headers: { Authorization: `Bearer ${env("STRIPE_SECRET_KEY")}`, "Content-Type": "application/x-www-form-urlencoded" }, body: params.toString() }).catch(() => null); return { ok: Boolean(r?.ok), body: await r?.json?.().catch(() => ({})) }; }
async function resend(to, subject, text) { if (!env("RESEND_API_KEY") || !env("RESEND_FROM_EMAIL")) return { ok: false }; const r = await fetch("https://api.resend.com/emails", { method: "POST", headers: { Authorization: `Bearer ${env("RESEND_API_KEY")}`, "Content-Type": "application/json" }, body: JSON.stringify({ from: env("RESEND_FROM_EMAIL"), to: [to], subject, text }) }).catch(() => null); return { ok: Boolean(r?.ok) }; }

function validateIntake(b) { const value = { company_name: clean(b.company_name || b.companyName), contact_name: clean(b.contact_name || b.contactName || b.name), email: clean(b.email).toLowerCase(), phone: clean(b.phone), industry: clean(b.industry), budget: clean(b.budget), timeline: clean(b.timeline), goals: clean(b.goals || b.message), current_website: clean(b.current_website || b.currentWebsite), needed_services: Array.isArray(b.needed_services) ? b.needed_services.map(clean).filter(Boolean) : list(b.needed_services || b.neededServices) }; const missing = ["company_name", "contact_name", "email", "goals"].filter((k) => !value[k]); if (missing.length) return { ok: false, code: "validation_failed", missing }; if (!/^\S+@\S+\.\S+$/.test(value.email)) return { ok: false, code: "validation_failed", message: "Enter a valid email." }; return { ok: true, value }; }
function verifySig(raw, header, secret) { if (!header || !Buffer.isBuffer(raw)) return false; const p = Object.fromEntries(header.split(",").map((x) => x.split("="))); if (!p.t || !p.v1) return false; const expected = crypto.createHmac("sha256", secret).update(`${p.t}.${raw.toString("utf8")}`).digest("hex"); const a = Buffer.from(expected); const b = Buffer.from(p.v1); return a.length === b.length && crypto.timingSafeEqual(a, b); }
function priceId(key) { const p = PRODUCTS[key]; return env([p[3], ...(p[4] || [])]); }
function productDescription(key) { return { business_builder_monthly: "Offer setup, intake, launch checklist, customer operations, and billing readiness.", business_builder_onetime: "One-time setup package for turning a service idea into a launch-ready operating workflow.", creator_studio_monthly: "Creative release planning, asset organization, campaign packaging, and audience workflow management.", growth_studio_monthly: "Outreach tracking, offers, growth experiments, and campaign operating rhythm." }[key]; }
function stripeOk() { return env("STRIPE_SECRET_KEY")?.startsWith("sk_"); }
function founders() { return new Set(list(env(["FOUNDER_EMAILS", "SONARA_ADMIN_EMAILS"])).map((x) => x.toLowerCase())); }
function admins() { return new Set(list(env(["ADMIN_EMAILS", "ADMIN_EMAIL", "SONARA_ADMIN_EMAILS"])).map((x) => x.toLowerCase())); }
function env(k) { return Array.isArray(k) ? k.map((x) => process.env[x]).find(Boolean) : process.env[k]; }
function list(v) { return String(v || "").split(/[;,\n]/).map((x) => x.trim()).filter(Boolean); }
function clean(v) { return String(v || "").trim().slice(0, 2000); }
function pick(o, keys) { return Object.fromEntries(keys.filter((k) => o[k] !== undefined).map((k) => [k, o[k]])); }
function safeTable(t) { return /^[a-z_]+$/.test(t); }
function uuid(v) { return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(v || "")); }
function setup(service) { return { ok: false, code: "setup_required", service, message: `${service} is not configured.` }; }
function bearer(req) { return String(req.get("authorization") || "").match(/^Bearer\s+(.+)$/i)?.[1] || ""; }
function cookie(req, name) { return String(req.get("cookie") || "").split(";").map((x) => x.trim()).find((x) => x.startsWith(`${name}=`))?.slice(name.length + 1) || ""; }
function setCookie(res, name, token, maxAge) { res.cookie(name, token, { httpOnly: true, sameSite: "lax", secure: process.env.NODE_ENV === "production", path: "/", maxAge: Math.min(Number(maxAge) || COOKIE_MAX_AGE, COOKIE_MAX_AGE) * 1000 }); }
function clearCookie(res, name) { res.clearCookie(name, { httpOnly: true, sameSite: "lax", secure: process.env.NODE_ENV === "production", path: "/" }); }
function wantsJson(req) { return Boolean(req.is("application/json")) || String(req.get("accept") || "").includes("application/json"); }
function publicUrl(req) { return (env(["NEXT_PUBLIC_SITE_URL", "PUBLIC_SITE_URL", "APP_URL"]) || `${req.protocol}://${req.get("host") || "localhost:3000"}`).replace(/\/$/, ""); }
function setupPage(req, res) { return wantsJson(req) ? res.status(503).json(setup("account_database")) : res.status(503).type("html").send(responsePage("Account database setup required", "Supabase URL, anon key, and service role key are required for protected SaaS pages.", [link("/api/readiness", "Readiness API"), link("/", "Home")])); }
function jsonOrHtml(req, res, status, payload, redirect) { if (wantsJson(req)) return res.status(status).json(payload); return status < 300 && redirect ? res.redirect(303, redirect) : res.status(status).type("html").send(responsePage(payload.ok ? "Saved" : "Not saved", payload.message || payload.code, [link("/dashboard", "Dashboard")])); }

function page(res, title, eyebrow, heading, body, sections, actions) { res.type("html").send(layout({ title, eyebrow, heading, body, sections, actions })); }
function layout({ title, eyebrow, heading, body, sections = [], actions = [] }) { return `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><meta name="theme-color" content="#090912"><title>${esc(title)} | SONARA Industries</title><style>${css()}</style></head><body><div class="mesh" aria-hidden="true"></div><header><a class="brand" href="/">SONARA Industries</a><nav aria-label="Primary"><a href="/business-builder">Business Builder</a><a href="/creator-studio">Creator Studio</a><a href="/growth-studio">Growth Studio</a><a href="/pricing">Pricing</a><a href="/login">Login</a><a href="/dashboard">Dashboard</a><a href="/admin">Admin</a></nav></header><main><section class="hero"><p class="eyebrow">${esc(eyebrow)}</p><h1>${esc(heading)}</h1><p class="lede">${esc(body)}</p><div class="actions">${actions.join("")}</div></section><section class="grid">${sections.join("")}</section></main><footer><p>SONARA Industries builds launch infrastructure for small businesses, creators, and growth teams.</p><nav aria-label="Legal">${Object.entries(LEGAL).map(([s, v]) => `<a href="/${s}">${esc(v[0])}</a>`).join("")}</nav></footer><script>document.querySelectorAll('[data-toggle-password]').forEach(function(b){b.addEventListener('click',function(){var i=document.getElementById(b.dataset.togglePassword);if(!i)return;var show=i.type==='password';i.type=show?'text':'password';b.textContent=show?'Hide password':'Show password';b.setAttribute('aria-pressed',String(show));});});document.querySelectorAll('[data-submit-label]').forEach(function(f){f.addEventListener('submit',function(){var b=f.querySelector('button[type="submit"]');if(b){b.disabled=true;b.textContent=f.dataset.submitLabel;}});});</script></body></html>`; }
function link(h, t) { return `<a class="action" href="${esc(h)}">${esc(t)}</a>`; }
function logout() { return `<form class="inline" method="post" action="/logout"><button class="action buttonish" type="submit">Logout</button></form>`; }
function adminLogout() { return `<form class="inline" method="post" action="/admin/logout"><button class="action buttonish" type="submit">Logout</button></form>`; }
function responsePage(title, body, actions) { return layout({ title, eyebrow: "System response", heading: title, body, sections: [], actions }); }
function card(title, body, href = "") { return `<article class="card"><h2>${esc(title)}</h2><p>${esc(body)}</p>${href ? `<a class="textlink" href="${esc(href)}">Open</a>` : ""}</article>`; }
function graphic(body) { return `<article class="card graphic"><div class="orb"></div><div class="nodes"><span></span><span></span><span></span></div><h2>Operating map</h2><p>${esc(body)}</p></article>`; }
function gate(title, body, ok) { return `<article class="card ${ok ? "ok" : "locked"}"><h2>${esc(title)}</h2><p>${esc(ok ? body : `Locked: ${body}`)}</p><p class="fine">${ok ? "Access granted by role or verified billing state." : "Upgrade or complete setup to unlock. No hardcoded paid access."}</p></article>`; }
function priceCard(name, price, desc, key) { return `<article class="card"><h2>${esc(name)}</h2><p class="price">${esc(price)}</p><p>${esc(desc)}</p>${key ? checkoutButton(key) : link("/signup", "Start Free")}</article>`; }
function checkoutButton(key) { const p = PRODUCTS[key]; const disabled = !stripeOk() || !priceId(key); return `<form method="post" action="/api/billing/create-checkout-session" data-submit-label="Opening checkout..."><input type="hidden" name="product" value="${esc(key)}"><button type="submit" ${disabled ? "disabled" : ""}>${disabled ? "Setup required" : "Checkout"}</button><p class="fine">${disabled ? `Requires ${p[3]} and STRIPE_SECRET_KEY.` : "Server-side Stripe Checkout."}</p></form>`; }
function checkoutCard(key) { const p = PRODUCTS[key]; return priceCard(p[1], p[2] === "payment" ? "One-time" : "Monthly", productDescription(key), key); }
function authPage(res, title, action, admin) { return page(res, title, admin ? "Founder access" : "Account access", title, admin ? "Founder/admin access is checked server-side by role or allowlisted email." : "Email/password access uses Supabase when configured.", [authForm(title, action)], [link("/signup", "Signup"), link("/login", "Login"), link("/", "Home")]); }
function authForm(title, action) { const id = `password-${action.replace(/\W/g, "")}`; return `<article class="card"><h2>${esc(title)}</h2><form method="post" action="${esc(action)}" data-submit-label="Checking access..."><label>Email<input name="email" type="email" autocomplete="email" required></label><label>Password<div class="password-row"><input id="${id}" name="password" type="password" autocomplete="current-password" required minlength="6"><button type="button" data-toggle-password="${id}" aria-pressed="false">Show password</button></div></label><label>Full name<input name="full_name" type="text" autocomplete="name"></label><button type="submit">Continue</button><p class="fine">Google login is deferred unless OAuth provider variables are configured.</p></form></article>`; }
function intakeForm() { return `<article class="card"><h2>Intake request</h2><form method="post" action="/api/business-builder/intake" data-submit-label="Saving intake..."><label>Company name<input name="company_name" required></label><label>Contact name<input name="contact_name" required></label><label>Email<input name="email" type="email" required></label><label>Phone<input name="phone" type="tel"></label><label>Industry<input name="industry"></label><label>Budget<input name="budget"></label><label>Timeline<input name="timeline"></label><label>Current website<input name="current_website" type="url"></label><label>Needed services<input name="needed_services" placeholder="website, payments, email"></label><label>Goals<textarea name="goals" required></textarea></label><button type="submit">Submit intake</button></form></article>`; }
function supportForm() { return `<article class="card"><h2>Support</h2><form method="post" action="/support" data-submit-label="Saving request..."><label>Subject<input name="subject" required></label><label>Message<textarea name="message" required></textarea></label><button type="submit">Create support request</button></form></article>`; }
function roleCard(a) { return card("Role", `Current roles: ${(a.roles || ["customer"]).join(", ")}`); }
function readinessCard() { const r = ready(); return `<article class="card"><h2>Environment readiness</h2>${Object.entries(r).filter(([k]) => k !== "ok").map(([k, v]) => `<p><strong>${esc(label(k))}:</strong> ${esc(v)}</p>`).join("")}</article>`; }
function checklistCard(r) { return `<article class="card"><h2>Checklist</h2>${r.items?.length ? r.items.map((i) => `<p><strong>${esc(i.title)}:</strong> ${esc(i.status || "todo")}</p>`).join("") : "<p>No checklist items yet.</p>"}<form method="post" action="/api/business-builder/checklist"><label>New checklist item<input name="title" required></label><button type="submit">Add checklist item</button></form></article>`; }
function billingCard(b) { if (!b.ok) return card("Current plan", b.message); return `<article class="card"><h2>Current plan</h2>${b.subscriptions.length ? b.subscriptions.map((s) => `<p>Subscription: ${esc(s.status)} ${esc(s.price_id || "")}</p>`).join("") : "<p>No active subscription records yet.</p>"}${b.purchases.length ? b.purchases.map((p) => `<p>Purchase: ${esc(p.product_key)} ${esc(p.status)}</p>`).join("") : "<p>No one-time purchases yet.</p>"}<form method="post" action="/api/billing/create-portal-session"><button type="submit" ${stripeOk() ? "" : "disabled"}>Manage billing portal</button></form></article>`; }
function activityCard(events) { const rows = Array.isArray(events) ? events : []; return `<article class="card"><h2>Recent activity</h2>${rows.length ? rows.map((e) => `<p><strong>${esc(e.event_type || e.action || "activity")}</strong><br><span class="fine">${esc(e.created_at || "")}</span></p>`).join("") : "<p>No activity yet.</p>"}</article>`; }
function auditCard(rows) { return `<article class="card"><h2>Audit logs</h2>${rows.length ? rows.map((e) => `<p>${esc(e.action)} <span class="fine">${esc(e.created_at || "")}</span></p>`).join("") : "<p>No audit logs yet.</p>"}</article>`; }
function adminCards(o) { return `<article class="card"><h2>Operational counts</h2>${Object.entries(o.counts || {}).map(([k, v]) => `<p><strong>${esc(label(k))}:</strong> ${esc(v)}</p>`).join("")}</article>`; }
function distinctFeatureCopy(slug, feature) { return `${feature} for ${COMPANIES[slug].name}: practical workflow, clear next action, and setup-required states when external services are missing.`; }
function label(v) { return String(v).replace(/_/g, " ").replace(/([A-Z])/g, " $1").replace(/^./, (c) => c.toUpperCase()); }
function css() { return `:root{color-scheme:dark;--bg:#07070b;--panel:rgba(18,18,28,.78);--line:rgba(255,255,255,.14);--text:#f8f4ec;--muted:#b8b0c3;--gold:#d8b86f;--bad:#ff9d9d;--ok:#98f5c1}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at 10% 0%,#2a2038 0,#07070b 34rem),#07070b;color:var(--text);font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}.mesh{position:fixed;inset:0;pointer-events:none;background:radial-gradient(circle at 80% 20%,rgba(216,184,111,.16),transparent 24rem);opacity:.9}header,main,footer{width:min(1160px,calc(100% - 36px));margin:auto;position:relative}header{display:flex;align-items:center;justify-content:space-between;gap:18px;padding:26px 0}nav,.actions{display:flex;flex-wrap:wrap;gap:10px}.brand,.eyebrow{letter-spacing:.18em;text-transform:uppercase;color:var(--gold);font-size:13px;text-decoration:none}.hero{padding:60px 0 34px}h1{font-size:clamp(42px,8vw,92px);line-height:.95;margin:12px 0;letter-spacing:-.05em}h2{margin:0 0 10px}.lede,p{color:var(--muted);line-height:1.65}.lede{font-size:20px;max-width:760px}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(270px,1fr));gap:16px;margin:22px 0 48px}.card{border:1px solid var(--line);background:var(--panel);backdrop-filter:blur(16px);border-radius:22px;padding:22px;min-height:170px;box-shadow:0 24px 80px rgba(0,0,0,.28);overflow-wrap:anywhere}.card.ok{border-color:rgba(152,245,193,.55)}.card.locked{border-color:rgba(255,157,157,.45)}.action,button{border:1px solid var(--line);border-radius:999px;min-height:44px;padding:11px 15px;background:rgba(255,255,255,.04);color:var(--text);text-decoration:none;display:inline-flex;align-items:center;justify-content:center;font:inherit}.buttonish,button[type=submit]{background:var(--gold);color:#121212;font-weight:800}button:disabled{opacity:.55;cursor:not-allowed;background:#35313b;color:var(--muted)}a:hover,.action:hover,button:hover{border-color:var(--gold)}a:focus-visible,button:focus-visible,input:focus-visible,textarea:focus-visible,select:focus-visible{outline:3px solid var(--gold);outline-offset:3px}form{display:grid;gap:14px}.inline{display:inline}.inline button{width:auto}label{display:grid;gap:6px;color:var(--text)}input,textarea,select{width:100%;border:1px solid var(--line);background:#0b0b12;color:var(--text);border-radius:14px;padding:12px 14px;font:inherit;min-height:44px}textarea{min-height:110px}.password-row{display:grid;grid-template-columns:1fr auto;gap:8px}.fine{font-size:13px}.price{font-size:24px;color:var(--text)}.textlink{color:var(--gold)}footer{border-top:1px solid var(--line);padding:26px 0 40px}.graphic{position:relative;overflow:hidden}.orb{width:140px;height:140px;border-radius:50%;background:radial-gradient(circle,var(--gold),transparent 70%);opacity:.35}.nodes{display:flex;gap:8px}.nodes span{width:42px;height:42px;border:1px solid var(--line);border-radius:14px;background:rgba(255,255,255,.05)}@media(max-width:760px){header{align-items:flex-start;flex-direction:column}.hero{padding-top:34px}.password-row{grid-template-columns:1fr}.grid{grid-template-columns:1fr}}`; }
function esc(v) { return String(v ?? "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#39;"); }

module.exports = app;
if (require.main === module) app.listen(Number(process.env.PORT || 3000), () => console.log(`SONARA Industries listening on ${process.env.PORT || 3000}`));
